  "cron": "",
  "period": -1,
  "code": "
    if ((#SoundSensor).soundsensor_sound > 50) {
      (#Speaker).speaker_stop()
    }
  "
}

{
  "name": "Turn on light when brightness falls below 100 lux",
  "cron": "0 * * * *",
  "period": 100,
  "code": "
    light_on := false
    if ((#LightSensor).lightsensor_brightness < 100) {
      if (light_on == false) {
        (#Light).switch_on()
        light_on = true
      }
    } else {
      light_on = false
    }
  "
}

{
  "name": "Raining and High Humidity",
  "cron": "",
  "period": -1,
  "code": "
    if ((#RainSensor).rainsensor_rain == true and (#HumiditySensor).humiditysensor_humidity >= 80.0) {
      (#Dehumidifier).dehumidifier_setdehumidifiermode(\"drying\")
      (#Speaker).speaker_speak(\"비가 오고 습도가 높습니다\")
    }
  "
}

{
  "name": "Door Opener",
  "cron": "0 * * * *",
  "period": 3600000,
  "code": "
    phase := false
    if (phase == false) {
      wait until ((#Door).doorControl_door == \"closed\")
      phase = true
    } else {
      (#Door).door_open()
    }
    if (phase == true) {
      (#Door).door_close()
      phase = false
    }
  "
}

{
  "name": "Valve Open/Close Loop",
  "cron": "0 13 * * *",
  "period": 300000,
  "code": "
    active := false
    if (active == false) {
      wait until ((#Clock).clock_hour >= 13 and (#Clock).clock_hour < 15)
      active = true
    }
    if (active == true) {
      (#Valve).valve_open()
      wait until ((#Clock).clock_hour >= 15)
      active = false
    }
  "
}

{
  "name": "Toggle Air Purifier Mode",
  "cron": "",
  "period": 1800000,
  "code": "
    active := false
    if (active == false) {
      (#AirPurifier).airpurifier_setsleepmode()
      active = true
    } else {
      (#AirPurifier).airpurifier_setairpurifiermodemode(\"auto\")
      active = false
    }
  "
}

{
  "name": "AirPurifier Toggle",
  "cron": "",
  "period": 1800000,
  "code": "
    mode := \"sleep\"
    if (mode == \"sleep\") {
      (#AirPurifier).airpurifier_setsleepmode()
      mode = \"high\"
    } else {
      (#AirPurifier).airpurifier_sethighspeedmode()
      mode = \"sleep\"
    }
  "
}

